import React, { useState } from 'react';
import { motion } from 'framer-motion';
import { useNavigate } from 'react-router-dom';
import { formatDistanceToNow } from 'date-fns';
import { useSaveStatus } from '../stores/useSaveStatus';
import { AboutModal } from './AboutModal';

/**
 * Footer component with save status indicator, Privacy Policy, and About Us
 * Sticky footer at bottom with links, save status at bottom-right
 */
export const Footer: React.FC = () => {
  const navigate = useNavigate();
  const { status, lastSaveTime } = useSaveStatus();
  const [showAboutModal, setShowAboutModal] = useState(false);

  // Simplified status text
  const getStatusText = () => {
    switch (status) {
      case 'saving':
        return 'Saving...';
      case 'saved':
        return lastSaveTime ? formatDistanceToNow(lastSaveTime, { addSuffix: true }) : 'Saved';
      case 'error':
        return 'Failed';
      default:
        return 'Saved';
    }
  };

  return (
    <>
      {/* Main Footer - Centered Floating Pill */}
      <motion.footer
        initial={{ opacity: 0, y: 50 }}
        animate={{ opacity: 1, y: 0 }}
        transition={{ duration: 0.3, ease: [0.4, 0, 0.2, 1] }}
        className="fixed bottom-4 left-1/2 transform -translate-x-1/2 z-30 pointer-events-none"
      >
        <div className="flex items-center gap-4 px-6 py-3 bg-white/90 dark:bg-surface-dark/90 backdrop-blur-lg rounded-full border border-border-light dark:border-border-dark pointer-events-auto shadow-lg">
          {/* Footer Links */}
          <div className="flex items-center gap-4 text-xs">
            <button
              onClick={() => setShowAboutModal(true)}
              className="text-text-light-secondary dark:text-text-dark-secondary hover:text-accent-blue dark:hover:text-accent-blue-hover transition-colors"
            >
              About Us
            </button>
            <span className="text-border-light dark:text-border-dark">|</span>
            <button
              onClick={() => navigate('/privacy')}
              className="text-text-light-secondary dark:text-text-dark-secondary hover:text-accent-blue dark:hover:text-accent-blue-hover transition-colors"
            >
              Privacy Policy
            </button>
            <span className="text-border-light dark:text-border-dark">|</span>
            <span className="text-text-light-secondary dark:text-text-dark-secondary">
              © {new Date().getFullYear()} Neuman Brain
            </span>
          </div>

          {/* Save Status (hidden on mobile) */}
          <div className="hidden sm:flex items-center gap-2 ml-2 pl-4 border-l border-border-light dark:border-border-dark">
            {/* Status Dot */}
            <span
              className={`w-2.5 h-2.5 rounded-full ${
                status === 'saving'
                  ? 'bg-blue-500 animate-pulse'
                  : status === 'saved'
                  ? 'bg-green-500'
                  : status === 'error'
                  ? 'bg-red-500'
                  : 'bg-neutral-400'
              }`}
            />

            {/* Status Text */}
            <span className="text-xs font-medium text-text-light-primary dark:text-text-dark-primary">
              {getStatusText()}
            </span>
          </div>
        </div>
      </motion.footer>

      {/* About Modal */}
      {showAboutModal && <AboutModal onClose={() => setShowAboutModal(false)} />}
    </>
  );
};
